import time
class TokenBucket:
    def __init__(self, rate, capacity):
        self.rate = rate
        self.capacity = capacity
        self.tokens = capacity
        self.last = time.time()
    def consume(self):
        now = time.time()
        self.tokens += (now - self.last) * self.rate
        self.last = now
        self.tokens = min(self.tokens, self.capacity)
        if self.tokens >= 1:
            self.tokens -= 1
            return True
        return False

